65	/// Result of parsing positional `..` notation.
66	///
67	/// Counts are `Some(0)` for closed sides and `None` for open (dotted) sides.
68	/// Open sides become unlimited unless a positional count is applied later.
69	#[derive(Debug, Clone, PartialEq, Eq)]
70	pub struct DotSpec {
71	    /// The bare revision (without `..`).
72	    pub rev: String,
73	    /// Descendant count: `None` = open (dotted), `Some(0)` = closed.
74	    pub desc_count: Option<usize>,
75	    /// Ancestor count: `None` = open (dotted), `Some(0)` = closed.
76	    pub anc_count: Option<usize>,
77	}
