79	/// Parse a positional REV string for `..` notation.
80	///
81	/// Returns the bare revision with open/closed counts per side.
82	/// `None` means the side had dots (open for expansion);
83	/// `Some(0)` means no dots on that side (closed).
84	/// Actual counts are applied later from positional args.
85	pub fn parse_dot_rev(rev: &str) -> DotSpec {
86	    if let Some(inner) = rev.strip_prefix("..").and_then(|s| s.strip_suffix("..")) {
87	        DotSpec {
88	            rev: inner.to_string(),
89	            desc_count: None,
90	            anc_count: None,
91	        }
92	    } else if let Some(inner) = rev.strip_prefix("..") {
93	        DotSpec {
94	            rev: inner.to_string(),
95	            desc_count: None,
96	            anc_count: Some(0),
97	        }
98	    } else if let Some(inner) = rev.strip_suffix("..") {
99	        DotSpec {
100	            rev: inner.to_string(),
101	            desc_count: Some(0),
102	            anc_count: None,
103	        }
104	    } else {
105	        DotSpec {
106	            rev: rev.to_string(),
107	            desc_count: Some(0),
108	            anc_count: Some(0),
109	        }
110	    }
111	}
