241	/// Indent all lines after the first by `n` spaces.
242	///
243	/// Returns the string unchanged if `n == 0` or there is only one line.
244	pub fn indent_body(s: &str, n: usize) -> String {
245	    if n == 0 {
246	        return s.to_string();
247	    }
248	    let pad = " ".repeat(n);
249	    let mut lines = s.lines();
250	    let mut result = match lines.next() {
251	        Some(first) => first.to_string(),
252	        None => return String::new(),
253	    };
254	    for line in lines {
255	        result.push('\n');
256	        if !line.is_empty() {
257	            result.push_str(&pad);
258	        }
259	        result.push_str(line);
260	    }
261	    result
262	}
