339	/// Format: changeID commitID [bookmarks |] first-line, then remaining description lines.
340	///
341	/// Same header rules as `format_commit_short`; body lines follow unchanged.
342	pub fn format_commit_full(commit: &Commit, bookmarks: &str) -> String {
343	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
344	    let change_short = &change_hex[..change_hex.len().min(12)];
345	    let commit_hex = commit.id().hex();
346	    let commit_short = &commit_hex[..commit_hex.len().min(12)];
347	    let desc = commit.description();
348	    if desc.is_empty() {
349	        return if bookmarks.is_empty() {
350	            format!("{change_short} {commit_short} (no description set)")
351	        } else {
352	            format!("{change_short} {commit_short} {bookmarks} | (no description set)")
353	        };
354	    }
355	    let mut lines = desc.lines();
356	    let first_line = lines.next().unwrap_or(""); // OK: obvious
357	    let mut result = if bookmarks.is_empty() {
358	        format!("{change_short} {commit_short} {first_line}")
359	    } else {
360	        format!("{change_short} {commit_short} {bookmarks} | {first_line}")
361	    };
362	    for line in lines {
363	        result.push('\n');
364	        result.push_str(line);
365	    }
366	    result
367	}
