369	/// Collect commit IDs for `..x..` (both directions) or any dot notation.
370	///
371	/// Returns `(commit_ids, anchor_index)` — the IDs in display order
372	/// (descendants closest to anchor, anchor, ancestors closest to anchor)
373	/// and the index of the anchor commit within the list.
374	///
375	/// - `desc_count`: `Some(n)` = n closest descendants, `None` = all, `Some(0)` = none
376	/// - `anc_count`: `Some(n)` = n closest ancestors, `None` = all, `Some(0)` = none
377	pub fn collect_ids(
378	    workspace: &Workspace,
379	    repo: &Arc<ReadonlyRepo>,
380	    rev: &str,
381	    desc_count: Option<usize>,
382	    anc_count: Option<usize>,
383	) -> Result<(Vec<CommitId>, usize), Box<dyn std::error::Error>> {
384	    let anchor_ids = resolve_revset(workspace, repo, rev)?;
385	    if anchor_ids.is_empty() {
386	        return Err(format!("no commit found for revision '{rev}'").into());
387	    }
388	    let anchor_id = &anchor_ids[0];
389	    let root_commit_id = repo.store().root_commit_id().clone();
390	
391	    // Descendants (closest to anchor)
392	    let mut desc_ids: Vec<CommitId> = Vec::new();
393	    if desc_count != Some(0) {
394	        let descendant_ids = resolve_revset(workspace, repo, &format!("{rev}::"))?;
395	        desc_ids = descendant_ids
396	            .into_iter()
397	            .filter(|id| *id != root_commit_id && *id != *anchor_id)
398	            .collect();
399	        if let Some(n) = desc_count {
400	            let start = desc_ids.len().saturating_sub(n);
401	            desc_ids = desc_ids[start..].to_vec();
402	        }
403	    }
404	
405	    // Ancestors (closest to anchor)
406	    let mut anc_ids: Vec<CommitId> = Vec::new();
407	    if anc_count != Some(0) {
408	        let ancestor_ids = resolve_revset(workspace, repo, &format!("::{rev}"))?;
409	        let limit = anc_count.unwrap_or(usize::MAX); // OK: no --ancestors limit → unbounded
410	        let mut count = 0;
411	        for commit_id in ancestor_ids {
412	            if commit_id == root_commit_id || commit_id == *anchor_id {
413	                continue;
414	            }
415	            anc_ids.push(commit_id);
416	            count += 1;
417	            if count >= limit {
418	                break;
419	            }
420	        }
421	    }
422	
423	    let anchor_index = desc_ids.len();
424	    let mut result = desc_ids;
425	    result.push(anchor_id.clone());
426	    result.extend(anc_ids);
427	    Ok((result, anchor_index))
428	}
