450	/// Expand comma-separated repo paths, default to `["."]`, and run a closure for each.
451	///
452	/// Header style controls output between repos.
453	/// Continues past errors, printing them to stderr, and returns an error if any failed.
454	pub fn for_each_repo<F>(
455	    raw_repos: &[PathBuf],
456	    header: &Header,
457	    mut body: F,
458	) -> Result<(), Box<dyn std::error::Error>>
459	where
460	    F: FnMut(&Workspace, &Arc<ReadonlyRepo>) -> Result<(), Box<dyn std::error::Error>>,
461	{
462	    let repos: Vec<PathBuf> = if raw_repos.is_empty() {
463	        vec![PathBuf::from(".")]
464	    } else {
465	        raw_repos
466	            .iter()
467	            .flat_map(|p| {
468	                p.to_string_lossy()
469	                    .split(',')
470	                    .map(|s| PathBuf::from(s.trim()))
471	                    .collect::<Vec<_>>()
472	            })
473	            .collect()
474	    };
475	    let multi = repos.len() > 1;
476	    let mut first = true;
477	    let mut errors: Vec<String> = Vec::new();
478	
479	    for repo_path in &repos {
480	        if multi {
481	            match header {
482	                Header::Label(deco) => {
483	                    if !first {
484	                        info!("");
485	                    }
486	                    info!(
487	                        "{}",
488	                        bold(&format!("{deco} {} {deco}", repo_path.display()))
489	                    );
490	                }
491	                Header::None => {}
492	            }
493	        }
494	        first = false;
495	
496	        match load_repo(repo_path) {
497	            Ok((workspace, repo)) => {
498	                if let Err(e) = body(&workspace, &repo) {
499	                    error!("({}): {e}", repo_path.display());
500	                    errors.push(format!("{}: {e}", repo_path.display()));
501	                }
502	            }
503	            Err(e) => {
504	                error!("({}): {e}", repo_path.display());
505	                errors.push(format!("{}: {e}", repo_path.display()));
506	            }
507	        }
508	    }
509	
510	    if errors.is_empty() {
511	        Ok(())
512	    } else {
513	        Err(format!("{} repo(s) had errors", errors.len()).into())
514	    }
515	}
