517	pub fn load_repo(
518	    path: &Path,
519	) -> Result<(Workspace, Arc<ReadonlyRepo>), Box<dyn std::error::Error>> {
520	    let config = StackedConfig::with_defaults();
521	    let settings = UserSettings::from_config(config)?;
522	    let store_factories = StoreFactories::default();
523	    let working_copy_factories = default_working_copy_factories();
524	
525	    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
526	    let repo = workspace.repo_loader().load_at_head().block_on()?;
527	
528	    Ok((workspace, repo))
529	}
